SELECT t.id AS taskId, t.title, t.description, a.name AS assignerName, ad.name AS assignerDept, e.name AS executorName, ed.name AS executorDept, t.importance, t.urgency, t.level, t.status, t.created_at AS createdAt, t.completion_deadline AS completionDeadline, t.completion_time AS completionTime FROM tasks t LEFT JOIN users a ON t.assigner_id = a.id LEFT JOIN departments ad ON a.dept_id = ad.id LEFT JOIN users e ON t.executor_id = e.id LEFT JOIN departments ed ON e.dept_id = ed.id
AND t.created_at >= #{startDate}
AND t.created_at <= #{endDate}
ORDER BY t.created_at DESC
